    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n * kernel/power/main.c - PM subsystem core functionality.\n *\n * Copyright (c) 2003 Patrick Mochel\n * Copyright (c) 2003 Open Source Development Lab\n */\n\n#include <linux/acpi.h>\n#include <linux/export.h>\n#include <linux/init.h>\n#include <linux/kobject.h>\n#include <linux/string.h>\n#include <linux/pm-trace.h>\n#include <linux/workqueue.h>\n#include <linux/debugfs.h>\n#include <linux/seq_file.h>\n#include <linux/suspend.h>\n#include <linux/syscalls.h>\n#include <linux/pm_runtime.h>\n#include <linux/atomic.h>\n#include <linux/wait.h>\n\n#include \"power.h\"\n\n#ifdef CONFIG_PM_SLEEP\n/*\n * The following functions are used by the suspend/hibernate code to temporarily\n * change gfp_allowed_mask in order to avoid using I/O during memory allocations\n * while devices are suspended.  To avoid races with the suspend/hibernate code,\n * they should always be called with system_transition_mutex held\n * (gfp_allowed_mask also should only be modified with system_transition_mutex\n * held, unless the suspend/hibernate code is guaranteed not to run in parallel\n * with that modification).\n */\nstatic unsigned int saved_gfp_count;\nstatic gfp_t saved_gfp_mask;\n\nvoid pm_restore_gfp_mask_safe(void)\n{\n\tif (!saved_gfp_count)\n\t\treturn;\n\tpm_restore_gfp_mask();\n}\n\nvoid pm_restore_gfp_mask(void)\n{\n\tWARN_ON(!mutex_is_locked(&system_transition_mutex));\n\n\tif (WARN_ON(!saved_gfp_count) || --saved_gfp_count)\n\t\treturn;\n\n\tgfp_allowed_mask = saved_gfp_mask;\n\tsaved_gfp_mask = 0;\n\n\tpm_pr_dbg(\"GFP mask restored\\n\");\n}\n\nvoid pm_restrict_gfp_mask(void)\n{\n\tWARN_ON(!mutex_is_locked(&system_transition_mutex));\n\n\tif (saved_gfp_count++) {\n\t\tWARN_ON((saved_gfp_mask & ~(__GFP_IO | __GFP_FS)) != gfp_allowed_mask);\n\t\treturn;\n\t}\n\n\tsaved_gfp_mask = gfp_allowed_mask;\n\tgfp_allowed_mask &= ~(__GFP_IO | __GFP_FS);\n\n\tpm_pr_dbg(\"GFP mask restricted\\n\");\n}\n\nunsigned int l