    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n * kernel/power/hibernate.c - Hibernation (a.k.a suspend-to-disk) support.\n *\n * Copyright (c) 2003 Patrick Mochel\n * Copyright (c) 2003 Open Source Development Lab\n * Copyright (c) 2004 Pavel Machek <pavel@ucw.cz>\n * Copyright (c) 2009 Rafael J. Wysocki, Novell Inc.\n * Copyright (C) 2012 Bojan Smojver <bojan@rexursive.com>\n */\n\n#define pr_fmt(fmt) \"PM: hibernation: \" fmt\n\n#include <crypto/acompress.h>\n#include <linux/blkdev.h>\n#include <linux/export.h>\n#include <linux/suspend.h>\n#include <linux/reboot.h>\n#include <linux/string.h>\n#include <linux/device.h>\n#include <linux/async.h>\n#include <linux/delay.h>\n#include <linux/fs.h>\n#include <linux/mount.h>\n#include <linux/pm.h>\n#include <linux/nmi.h>\n#include <linux/console.h>\n#include <linux/cpu.h>\n#include <linux/freezer.h>\n#include <linux/gfp.h>\n#include <linux/syscore_ops.h>\n#include <linux/ctype.h>\n#include <linux/ktime.h>\n#include <linux/security.h>\n#include <linux/secretmem.h>\n#include <trace/events/power.h>\n\n#include \"power.h\"\n\n\nstatic int nocompress;\nstatic int noresume;\nstatic int nohibernate;\nstatic int resume_wait;\nstatic unsigned int resume_delay;\nstatic char resume_file[256] = CONFIG_PM_STD_PARTITION;\ndev_t swsusp_resume_device;\nsector_t swsusp_resume_block;\n__visible int in_suspend __nosavedata;\n\nstatic char hibernate_compressor[CRYPTO_MAX_ALG_NAME] = CONFIG_HIBERNATION_DEF_COMP;\n\n/*\n * Compression/decompression algorithm to be used while saving/loading\n * image to/from disk. This would later be used in 'kernel/power/swap.c'\n * to allocate comp streams.\n */\nchar hib_comp_algo[CRYPTO_MAX_ALG_NAME];\n\nenum {\n\tHIBERNATION_INVALID,\n\tHIBERNATION_PLATFORM,\n\tHIBERNATION_SHUTDOWN,\n\tHIBERNATION_REBOOT,\n#ifdef CONFIG_SUSPEND\n\tHIBERNATION_SUSPEND,\n#endif\n\tHIBERNATION_TEST_RESUME,\n\t/* keep last */\n\t__HIBERNATION_AFTER_LAST\n};\n#define HIBERNATION_MAX (__HIBERNATION_AFTER_LAST-1)\n#define HIBERNATION_FIRST (HIBERNATION_INVALID + 1)\n\nstatic int hibernation_mode = HIBERNATION_SHUTDOWN;\n\nbool freezer_test_done;\n\nstatic const struct platform_hibernation_ops *hibernation_ops;\n\nstatic atomic_t hibernate_atomic = ATOMIC_INIT(1);\n\n#ifdef CONFIG_SUSPEND\n/**\n * pm_hibernation_mode_is_suspend - Check if hibernation has been set to suspend\n */\nbool pm_hibernation_mode_is_suspend(void)\n{\n\treturn hibernation_mode == HIBERNATION_SUSPEND;\n}\nEXPORT_SYMBOL_GPL(pm_hibernation_mode_is_suspend);\n#endif\n\nbool hibernate_acquire(void)\n{\n\treturn atomic_add_unless(&hibernate_atomic, -1, 0);\n}\n\nvoid hibernate_release(void)\n{\n\tatomic_inc(&hibernate_atomic);\n}\n\nbool hibernation_in_progress(void)\n{\n\treturn !atomic_read(&hibernate_atomic);\n}\n\nbool hibernation_available(void)\n{\n\treturn nohibernate == 0 &&\n\t\t!security_locked_down(LOCKDOWN_HIBERNATION) &&\n\t\t!secretmem_active() && !cxl_mem_active();\n}\n\n/**\n * hibernation_set_ops - Set the global hibernate operations.\n * @ops: Hibernation operations to use in subsequent hibernation transitions.\n */\nvoid hibernation_set_ops(const struct platform_hibernation_ops *ops)\n{\n\tunsigned int sleep_flags;\n\n\tif (ops && !(ops->begin && ops->end &&  ops->pre_snapshot\n\t    && ops->prepare && ops->finish && ops->enter && ops->pre_restore\n\t    && ops->restore_cleanup && ops->leave)) {\n\t\tWARN_ON(1);\n\t\treturn;\n\t}\n\n\tsleep_flags = lock_system_sleep();\n\n\thibernation_ops = ops;\n\tif (ops)\n\t\thibernation_mode = HIBERNATION_PLATFORM;\n\telse if (hibernation_mode == HIBERNATION_PLATFORM)\n\t\thibernation_mode = HIBERNATION_SHUTDOWN;\n\n\tunlock_system_sleep(sleep_flags);\n}\nEXPORT_SYMBOL_GPL(hibernation_set_ops);\n\nstatic bool entering_platform_hibernation;\n\nbool system_entering_hibernation(void)\n{\n\treturn entering_platform_hibernation;\n}\nEXPORT_SYMBOL(system_entering_hibernation);\n\n#ifdef CONFIG_PM_DEBUG\nstatic unsigned int pm_test_delay = 5;\nmodule_param(pm_test_delay, uint, 0644);\nMODULE_PARM_DESC(pm_test_delay,\n\t\t \"Number of seconds to wait before resuming from hibernation test\");\nstatic void hibernation_debug_sleep(void)\n{\n\tpr_info(\"hibernation debug: Waiting for %d second(s).\\n\",\n\t\tpm_test_delay);\n\tmdelay(pm_test_delay * 1000);\n}\n\nstatic int hibernation_test(int level)\n{\n\tif (pm_test_level == level) {\n\t\thibernation_debug_sleep();\n\t\treturn 1;\n\t}\n\treturn 0;\n}\n#else /* !CONFIG_PM_DEBUG */\nstatic int hibernation_test(int level) { return 0; }\n#endif /* !CONFIG_PM_DEBUG */\n\n/**\n * platform_begin - Call platform to start hibernation.\n * @platform_mode: Whether or not to use the platform driver.\n */\nstatic int platform_begin(int platform_mode)\n{\n\treturn (platform_mode && hibernation_ops) ?\n\t\thibernation_ops->begin(PMSG_FREEZE) : 0;\n}\n\n/**\n * platform_end - Call platform to finish transition to the working state.\n * @platform_mode: Whether or not to use the platform driver.\n */\nstatic void platform_end(int platform_mode)\n{\n\tif (platform_mode && hibernation_ops)\n\t\thibernation_ops->end();\n}\n\n/**\n * platform_pre_snapshot - Call platform to prepare the machine for hibernation.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Use the platform driver to prepare the system for creating a hibernate image,\n * if so configured, and return an error code if that fails.\n */\n\nstatic int platform_pre_snapshot(int platform_mode)\n{\n\treturn (platform_mode && hibernation_ops) ?\n\t\thibernation_ops->pre_snapshot() : 0;\n}\n\n/**\n * platform_leave - Call platform to prepare a transition to the working state.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Use the platform driver prepare to prepare the machine for switching to the\n * normal mode of operation.\n *\n * This routine is called on one CPU with interrupts disabled.\n */\nstatic void platform_leave(int platform_mode)\n{\n\tif (platform_mode && hibernation_ops)\n\t\thibernation_ops->leave();\n}\n\n/**\n * platform_finish - Call platform to switch the system to the working state.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Use the platform driver to switch the machine to the normal mode of\n * operation.\n *\n * This routine must be called after platform_prepare().\n */\nstatic void platform_finish(int platform_mode)\n{\n\tif (platform_mode && hibernation_ops)\n\t\thibernation_ops->finish();\n}\n\n/**\n * platform_pre_restore - Prepare for hibernate image restoration.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Use the platform driver to prepare the system for resume from a hibernation\n * image.\n *\n * If the restore fails after this function has been called,\n * platform_restore_cleanup() must be called.\n */\nstatic int platform_pre_restore(int platform_mode)\n{\n\treturn (platform_mode && hibernation_ops) ?\n\t\thibernation_ops->pre_restore() : 0;\n}\n\n/**\n * platform_restore_cleanup - Switch to the working state after failing restore.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Use the platform driver to switch the system to the normal mode of operation\n * after a failing restore.\n *\n * If platform_pre_restore() has been called before the failing restore, this\n * function must be called too, regardless of the result of\n * platform_pre_restore().\n */\nstatic void platform_restore_cleanup(int platform_mode)\n{\n\tif (platform_mode && hibernation_ops)\n\t\thibernation_ops->restore_cleanup();\n}\n\n/**\n * platform_recover - Recover from a failure to suspend devices.\n * @platform_mode: Whether or not to use the platform driver.\n */\nstatic void platform_recover(int platform_mode)\n{\n\tif (platform_mode && hibernation_ops && hibernation_ops->recover)\n\t\thibernation_ops->recover();\n}\n\n/**\n * swsusp_show_speed - Print time elapsed between two events during hibernation.\n * @start: Starting event.\n * @stop: Final event.\n * @nr_pages: Number of memory pages processed between @start and @stop.\n * @msg: Additional diagnostic message to print.\n */\nvoid swsusp_show_speed(ktime_t start, ktime_t stop,\n\t\t      unsigned nr_pages, char *msg)\n{\n\tktime_t diff;\n\tu64 elapsed_centisecs64;\n\tunsigned int centisecs;\n\tunsigned int k;\n\tunsigned int kps;\n\n\tdiff = ktime_sub(stop, start);\n\telapsed_centisecs64 = ktime_divns(diff, 10*NSEC_PER_MSEC);\n\tcentisecs = elapsed_centisecs64;\n\tif (centisecs == 0)\n\t\tcentisecs = 1;\t/* avoid div-by-zero */\n\tk = nr_pages * (PAGE_SIZE / 1024);\n\tkps = (k * 100) / centisecs;\n\tpr_info(\"%s %u kbytes in %u.%02u seconds (%u.%02u MB/s)\\n\",\n\t\tmsg, k, centisecs / 100, centisecs % 100, kps / 1000,\n\t\t(kps % 1000) / 10);\n}\n\n__weak int arch_resume_nosmt(void)\n{\n\treturn 0;\n}\n\n/**\n * create_image - Create a hibernation image.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Execute device drivers' \"late\" and \"noirq\" freeze callbacks, create a\n * hibernation image and run the drivers' \"noirq\" and \"early\" thaw callbacks.\n *\n * Control reappears in this routine after the subsequent restore.\n */\nstatic int create_image(int platform_mode)\n{\n\tint error;\n\n\terror = dpm_suspend_end(PMSG_FREEZE);\n\tif (error) {\n\t\tpr_err(\"Some devices failed to power down, aborting\\n\");\n\t\treturn error;\n\t}\n\n\terror = platform_pre_snapshot(platform_mode);\n\tif (error || hibernation_test(TEST_PLATFORM))\n\t\tgoto Platform_finish;\n\n\terror = pm_sleep_disable_secondary_cpus();\n\tif (error || hibernation_test(TEST_CPUS))\n\t\tgoto Enable_cpus;\n\n\tlocal_irq_disable();\n\n\tsystem_state = SYSTEM_SUSPEND;\n\n\terror = syscore_suspend();\n\tif (error) {\n\t\tpr_err(\"Some system devices failed to power down, aborting\\n\");\n\t\tgoto Enable_irqs;\n\t}\n\n\tif (hibernation_test(TEST_CORE) || pm_wakeup_pending())\n\t\tgoto Power_up;\n\n\tin_suspend = 1;\n\tsave_processor_state();\n\ttrace_suspend_resume(TPS(\"machine_suspend\"), PM_EVENT_HIBERNATE, true);\n\terror = swsusp_arch_suspend();\n\t/* Restore control flow magically appears here */\n\trestore_processor_state();\n\ttrace_suspend_resume(TPS(\"machine_suspend\"), PM_EVENT_HIBERNATE, false);\n\tif (error)\n\t\tpr_err(\"Error %d creating image\\n\", error);\n\n\tif (!in_suspend) {\n\t\tevents_check_enabled = false;\n\t\tclear_or_poison_free_pages();\n\t}\n\n\tplatform_leave(platform_mode);\n\n Power_up:\n\tsyscore_resume();\n\n Enable_irqs:\n\tsystem_state = SYSTEM_RUNNING;\n\tlocal_irq_enable();\n\n Enable_cpus:\n\tpm_sleep_enable_secondary_cpus();\n\n\t/* Allow architectures to do nosmt-specific post-resume dances */\n\tif (!in_suspend)\n\t\terror = arch_resume_nosmt();\n\n Platform_finish:\n\tplatform_finish(platform_mode);\n\n\tdpm_resume_start(in_suspend ?\n\t\t(error ? PMSG_RECOVER : PMSG_THAW) : PMSG_RESTORE);\n\n\treturn error;\n}\n\nstatic void shrink_shmem_memory(void)\n{\n\tstruct sysinfo info;\n\tunsigned long nr_shmem_pages, nr_freed_pages;\n\n\tsi_meminfo(&info);\n\tnr_shmem_pages = info.sharedram; /* current page count used for shmem */\n\t/*\n\t * The intent is to reclaim all shmem pages. Though shrink_all_memory() can\n\t * only reclaim about half of them, it's enough for creating the hibernation\n\t * image.\n\t */\n\tnr_freed_pages = shrink_all_memory(nr_shmem_pages);\n\tpr_debug(\"requested to reclaim %lu shmem pages, actually freed %lu pages\\n\",\n\t\t\tnr_shmem_pages, nr_freed_pages);\n}\n\n/**\n * hibernation_snapshot - Quiesce devices and create a hibernation image.\n * @platform_mode: If set, use platform driver to prepare for the transition.\n *\n * This routine must be called with system_transition_mutex held.\n */\nint hibernation_snapshot(int platform_mode)\n{\n\tpm_message_t msg;\n\tint error;\n\n\tpm_suspend_clear_flags();\n\terror = platform_begin(platform_mode);\n\tif (error)\n\t\tgoto Close;\n\n\t/* Preallocate image memory before shutting down devices. */\n\terror = hibernate_preallocate_memory();\n\tif (error)\n\t\tgoto Close;\n\n\terror = freeze_kernel_threads();\n\tif (error)\n\t\tgoto Cleanup;\n\n\tif (hibernation_test(TEST_FREEZER)) {\n\n\t\t/*\n\t\t * Indicate to the caller that we are returning due to a\n\t\t * successful freezer test.\n\t\t */\n\t\tfreezer_test_done = true;\n\t\tgoto Thaw;\n\t}\n\n\terror = dpm_prepare(PMSG_FREEZE);\n\tif (error) {\n\t\tdpm_complete(PMSG_RECOVER);\n\t\tgoto Thaw;\n\t}\n\n\t/*\n\t * Device drivers may move lots of data to shmem in dpm_prepare(). The shmem\n\t * pages will use lots of system memory, causing hibernation image creation\n\t * fail due to insufficient free memory.\n\t * This call is to force flush the shmem pages to swap disk and reclaim\n\t * the system memory so that image creation can succeed.\n\t */\n\tshrink_shmem_memory();\n\n\tconsole_suspend_all();\n\tpm_restrict_gfp_mask();\n\n\terror = dpm_suspend(PMSG_FREEZE);\n\n\tif (error || hibernation_test(TEST_DEVICES))\n\t\tplatform_recover(platform_mode);\n\telse\n\t\terror = create_image(platform_mode);\n\n\t/*\n\t * In the case that we call create_image() above, the control\n\t * returns here (1) after the image has been created or the\n\t * image creation has failed and (2) after a successful restore.\n\t */\n\n\t/* We may need to release the preallocated image pages here. */\n\tif (error || !in_suspend)\n\t\tswsusp_free();\n\n\tmsg = in_suspend ? (error ? PMSG_RECOVER : PMSG_THAW) : PMSG_RESTORE;\n\tdpm_resume(msg);\n\n\tif (error || !in_suspend)\n\t\tpm_restore_gfp_mask();\n\n\tconsole_resume_all();\n\tdpm_complete(msg);\n\n Close:\n\tplatform_end(platform_mode);\n\treturn error;\n\n Thaw:\n\tthaw_kernel_threads();\n Cleanup:\n\tswsusp_free();\n\tgoto Close;\n}\n\nint __weak hibernate_resume_nonboot_cpu_disable(void)\n{\n\treturn suspend_disable_secondary_cpus();\n}\n\n/**\n * resume_target_kernel - Restore system state from a hibernation image.\n * @platform_mode: Whether or not to use the platform driver.\n *\n * Execute device drivers' \"noirq\" and \"late\" freeze callbacks, restore the\n * contents of highmem that have not been restored yet from the image and run\n * the low-level code that will restore the remaining contents of memory and\n * switch to the just restored target kernel.\n */\nstatic int resume_target_kernel(bool platform_mode)\n{\n\tint error;\n\n\terror = dpm_suspend_end(PMSG_QUIESCE);\n\tif (error) {\n\t\tpr_err(\"Some devices failed to power down, aborting resume\\n\");\n\t\treturn error;\n\t}\n\n\terror = platform_pre_restore(platform_mode);\n\tif (error)\n\t\tgoto Cleanup;\n\n\tcpuidle_pause();\n\n\terror = hibernate_resume_nonboot_cpu_disable();\n\tif (error)\n\t\tgoto Enable_cpus;\n\n\tlocal_irq_disable();\n\tsystem_state = SYSTEM_SUSPEND;\n\n\terror = syscore_suspend();\n\tif (error)\n\t\tgoto Enable_irqs;\n\n\tsave_processor_state();\n\terror = restore_highmem();\n\tif (!error) {\n\t\terror = swsusp_arch_resume();\n\t\t/*\n\t\t * The code below is only ever reached in case of a failure.\n\t\t * Otherwise, execution continues at the place where\n\t\t * swsusp_arch_suspend() was called.\n\t\t */\n\t\tBUG_ON(!error);\n\t\t/*\n\t\t * This call to restore_highmem() reverts the changes made by\n\t\t * the previous one.\n\t\t */\n\t\trestore_highmem();\n\t}\n\t/*\n\t * The only reason why swsusp_arch_resume() can fail is memory being\n\t * very tight, so we have to free it as soon as we can to avoid\n\t * subsequent failures.\n\t */\n\tswsusp_free();\n\trestore_processor_state();\n\ttouch_softlockup_watchdog();\n\n\tsyscore_resume();\n\n Enable_irqs:\n\tsystem_state = SYSTEM_RUNNING;\n\tlocal_irq_enable();\n\n Enable_cpus:\n\tpm_sleep_enable_secondary_cpus();\n\n Cleanup:\n\tplatform_restore_cleanup(platform_mode);\n\n\tdpm_resume_start(PMSG_RECOVER);\n\n\treturn error;\n}\n\n/**\n * hibernation_restore - Quiesce devices and restore from a hibernation image.\n * @platform_mode: If set, use platform driver to prepare for the transition.\n *\n * This routine must be called with system_transition_mutex held.  If it is\n * successful, control reappears in the restored target kernel in\n * hibernation_snapshot().\n */\nint hibernation_restore(int platform_mode)\n{\n\tint error;\n\n\tpm_prepare_console();\n\tconsole_suspend_all();\n\terror = dpm_suspend_start(PMSG_QUIESCE);\n\tif (!error) {\n\t\terror = resume_target_kernel(platform_mode);\n\t\t/*\n\t\t * The above should either succeed and jump to the new kernel,\n\t\t * or return with an error. Otherwise things are just\n\t\t * undefined, so let's be paranoid.\n\t\t */\n\t\tBUG_ON(!error);\n\t}\n\tdpm_resume_end(PMSG_RECOVER);\n\tconsole_resume_all();\n\tpm_restore_console();\n\treturn error;\n}\n\n/**\n * hibernation_platform_enter - Power off the system using the platform driver.\n */\nint hibernation_platform_enter(void)\n{\n\tint error;\n\n\tif (!hibernation_ops)\n\t\treturn -ENOSYS;\n\n\t/*\n\t * We have cancelled the power transition by running\n\t * hibernation_ops->finish() before saving the image, so we should let\n\t * the firmware know that we're going to enter the sleep state after all\n\t */\n\terror = hibernation_ops->begin(PMSG_HIBERNATE);\n\tif (error)\n\t\tgoto Close;\n\n\tentering_platform_hibernation = true;\n\tconsole_suspend_all();\n\terror = dpm_suspend_start(PMSG_HIBERNATE);\n\tif (error) {\n\t\tif (hibernation_ops->recover)\n\t\t\thibernation_ops->recover();\n\t\tgoto Resume_devices;\n\t}\n\n\terror = dpm_suspend_end(PMSG_HIBERNATE);\n\tif (error)\n\t\tgoto Resume_devices;\n\n\terror = hibernation_ops->prepare();\n\tif (error)\n\t\tgoto Platform_finish;\n\n\terror = pm_sleep_disable_secondary_cpus();\n\tif (error)\n\t\tgoto Enable_cpus;\n\n\tlocal_irq_disable();\n\tsystem_state = SYSTEM_SUSPEND;\n\n\terror = syscore_suspend();\n\tif (error)\n\t\tgoto Enable_irqs;\n\n\tif (pm_wakeup_pending()) {\n\t\terror = -EAGAIN;\n\t\tgoto Power_up;\n\t}\n\n\thibernation_ops->enter();\n\t/* We should never get here */\n\twhile (1);\n\n Power_up:\n\tsyscore_resume();\n Enable_irqs:\n\tsystem_state = SYSTEM_RUNNING;\n\tlocal_irq_enable();\n\n Enable_cpus:\n\tpm_sleep_enable_secondary_cpus();\n\n Platform_finish:\n\thibernation_ops->finish();\n\n\tdpm_resume_start(PMSG_RESTORE);\n\n Resume_devices:\n\tentering_platform_hibernation = false;\n\tdpm_resume_end(PMSG_RESTORE);\n\tconsole_resume_all();\n\n Close:\n\thibernation_ops->end();\n\n\treturn error;\n}\n\n/**\n * power_down - Shut the machine down for hibernation.\n *\n * Use the platform driver, if configured, to put the system into the sleep\n * state corresponding to hibernation, or try to power it off or reboot,\n * depending on the value of hibernation_mode.\n */\nstatic void power_down(void)\n{\n\tint error;\n\n#ifdef CONFIG_SUSPEND\n\tif (hibernation_mode == HIBERNATION_SUSPEND) {\n\t\terror = suspend_devices_and_enter(mem_sleep_current);\n\t\tif (!error)\n\t\t\tgoto exit;\n\n\t\thibernation_mode = hibernation_ops ? HIBERNATION_PLATFORM :\n\t\t\t\t\t\t     HIBERNATION_SHUTDOWN;\n\t}\n#endif\n\n\tswitch (hibernation_mode) {\n\tcase HIBERNATION_REBOOT:\n\t\tkernel_restart(NULL);\n\t\tbreak;\n\tcase HIBERNATION_PLATFORM:\n\t\terror = hibernation_platform_enter();\n\t\tif (error == -EAGAIN || error == -EBUSY) {\n\t\t\tevents_check_enabled = false;\n\t\t\tpr_info(\"Wakeup event detected during hibernation, rolling back.\\n\");\n\t\t\tgoto exit;\n\t\t}\n\t\tfallthrough;\n\tcase HIBERNATION_SHUTDOWN:\n\t\tif (kernel_can_power_off()) {\n\t\t\tentering_platform_hibernation = true;\n\t\t\tkernel_power_off();\n\t\t\tentering_platform_hibernation = false;\n\t\t}\n\t\tbreak;\n\t}\n\tkernel_halt();\n\t/*\n\t * Valid image is on the disk, if we continue we risk serious data\n\t * corruption after resume.\n\t */\n\tpr_crit(\"Power down manually\\n\");\n\twhile (1)\n\t\tcpu_relax();\n\nexit:\n\t/* Restore swap signature. */\n\terror = swsusp_unmark();\n\tif (error)\n\t\tpr_err(\"Swap will be unusable! Try swapon -a.\\n\");\n}\n\nstatic int load_image_and_restore(void)\n{\n\tint error;\n\tunsigned int flags;\n\n\tpm_pr_dbg(\"Loading hibernation image.\\n\");\n\n\tlock_device_hotplug();\n\terror = create_basic_memory_bitmaps();\n\tif (error) {\n\t\tswsusp_close();\n\t\tgoto Unlock;\n\t}\n\n\terror = swsusp_read(&flags);\n\tswsusp_close();\n\tif (!error)\n\t\terror = hibernation_restore(flags & SF_PLATFORM_MODE);\n\n\tpr_err(\"Failed to load image, recovering.\\n\");\n\tswsusp_free();\n\tfree_basic_memory_bitmaps();\n Unlock:\n\tunlock_device_hotplug();\n\n\treturn error;\n}\n\n#define COMPRESSION_ALGO_LZO \"lzo\"\n#define COMPRESSION_ALGO_LZ4 \"lz4\"\n\n/**\n * hibernate - Carry out system hibernation, including saving the image.\n */\nint hibernate(void)\n{\n\tbool snapshot_test = false;\n\tunsigned int sleep_flags;\n\tint error;\n\n\tif (!hibernation_available()) {\n\t\tpm_pr_dbg(\"Hibernation not available.\\n\");\n\t\treturn -EPERM;\n\t}\n\n\t/*\n\t * Query for the compression algorithm support if compression is enabled.\n\t */\n\tif (!nocompress) {\n\t\tstrscpy(hib_comp_algo, hibernate_compressor);\n\t\tif (!crypto_has_acomp(hib_comp_algo, 0, CRYPTO_ALG_ASYNC)) {\n\t\t\tpr_err(\"%s compression is not available\\n\", hib_comp_algo);\n\t\t\treturn -EOPNOTSUPP;\n\t\t}\n\t}\n\n\tsleep_flags = lock_system_sleep();\n\t/* The snapshot device should not be opened while we're running */\n\tif (!hibernate_acquire()) {\n\t\terror = -EBUSY;\n\t\tgoto Unlock;\n\t}\n\n\tpr_info(\"hibernation entry\\n\");\n\tpm_prepare_console();\n\terror = pm_notifier_call_chain_robust(PM_HIBERNATION_PREPARE, PM_POST_HIBERNATION);\n\tif (error)\n\t\tgoto Restore;\n\n\terror = pm_sleep_fs_sync();\n\tif (error)\n\t\tgoto Notify;\n\n\tfilesystems_freeze(filesystem_freeze_enabled);\n\n\terror = freeze_processes();\n\tif (error)\n\t\tgoto Exit;\n\n\tlock_device_hotplug();\n\t/* Allocate memory management structures */\n\terror = create_basic_memory_bitmaps();\n\tif (error)\n\t\tgoto Thaw;\n\n\terror = hibernation_snapshot(hibernation_mode == HIBERNATION_PLATFORM);\n\tif (error || freezer_t